import { useState } from "react";
import { addRepaymentPlan } from "../services/debtService";

const RepaymentPlan = ({ debtId, onClose }) => {
  const [monthlyPaymentAmount, setMonthlyPaymentAmount] = useState("");
  const [dateStarted, setDateStarted] = useState("");
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleAdd = async () => {
    setLoading(true);
    setMessage(null);

    const request = {
      id: 0,
      debtId: debtId,
      monthlyPaymentAmount: parseFloat(monthlyPaymentAmount),
      dateStarted: dateStarted
    };

    try {
      const result = await addRepaymentPlan(request);

      if (result > 0) {
        setMessage("Payment plan added successfully");
      } else {
        setMessage("Failed to add payment plan");
      }
    } catch (error) {
      setMessage("Error calling API");
    }

    setLoading(false);
  };

  return (
    <div style={modalStyle}>
      <div style={modalContentStyle}>
        <h3>Add Repayment Plan</h3>

        <label>Monthly Payment Amount</label>
        <input
          type="number"
          value={monthlyPaymentAmount}
          onChange={(e) => setMonthlyPaymentAmount(e.target.value)}
        />

        <label>Date Started</label>
        <input
          type="date"
          value={dateStarted}
          onChange={(e) => setDateStarted(e.target.value)}
        />

        {message && <p>{message}</p>}

        <div style={{ marginTop: "10px" }}>
          <button onClick={handleAdd} disabled={loading}>
            Add
          </button>

          <button onClick={onClose} style={{ marginLeft: "10px" }}>
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

export default RepaymentPlan;
